using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Get weather forecast for a US location by latitude/longitude")]
    public static async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude (e.g. 39.7456)")] double latitude,
        [Description("Longitude (e.g. -97.0892)")] double longitude)
    {
        var client = httpClientFactory.CreateClient("weather");

        // NWS API: resolve grid point, then fetch forecast
        var pointUrl = $"/points/{latitude},{longitude}";
        using var pointDoc = await client.GetFromJsonAsync<JsonDocument>(pointUrl);
        var forecastUrl = pointDoc!.RootElement
            .GetProperty("properties")
            .GetProperty("forecast")
            .GetString()!;

        using var forecastDoc = await client.GetFromJsonAsync<JsonDocument>(forecastUrl);
        var periods = forecastDoc!.RootElement
            .GetProperty("properties")
            .GetProperty("periods")
            .EnumerateArray()
            .Take(3);

        return string.Join("\n\n", periods.Select(p =>
            $"""
            {p.GetProperty("name").GetString()}:
              {p.GetProperty("temperature").GetInt32()}°{p.GetProperty("temperatureUnit").GetString()}
              Wind: {p.GetProperty("windSpeed").GetString()} {p.GetProperty("windDirection").GetString()}
              {p.GetProperty("shortForecast").GetString()}
            """));
    }

    [McpServerTool, Description("Get active weather alerts for a US state")]
    public static async Task<string> GetAlerts(
        IHttpClientFactory httpClientFactory,
        [Description("Two-letter US state code (e.g. CA, NY)")] string state)
    {
        var client = httpClientFactory.CreateClient("weather");

        using var doc = await client.GetFromJsonAsync<JsonDocument>(
            $"/alerts/active?area={state}");

        var features = doc!.RootElement
            .GetProperty("features")
            .EnumerateArray()
            .Take(5);

        if (!features.Any())
            return $"No active alerts for {state}.";

        return string.Join("\n---\n", features.Select(f =>
        {
            var props = f.GetProperty("properties");
            return $"""
                Event: {props.GetProperty("event").GetString()}
                Area: {props.GetProperty("areaDesc").GetString()}
                Severity: {props.GetProperty("severity").GetString()}
                {props.GetProperty("headline").GetString()}
                """;
        }));
    }
}

